package com.flowledger.product.controller; import com.flowledger.product.dto.CategoryDtos.*; import com.flowledger.product.service.CategoryService; import jakarta.validation.*; import org.springframework.data.domain.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/v1/categories") public class CategoryController{private final CategoryService s;public CategoryController(CategoryService s){this.s=s;}@PostMapping @ResponseStatus(HttpStatus.CREATED)public Response create(@Valid @RequestBody Create d){return s.create(d);}@GetMapping public Page<Response> list(@RequestParam(required=false)String search,Pageable p){return s.list(search,p);}@GetMapping("/{id}")public Response get(@PathVariable UUID id){return s.get(id);}@PutMapping("/{id}")public Response update(@PathVariable UUID id,@Valid @RequestBody Update d){return s.update(id,d);}@DeleteMapping("/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)public void delete(@PathVariable UUID id){s.delete(id);}}